mapper.select:
SELECT v.VERSION_ID, v.PROJECT_ID, v.VERSION_NAME, v.STATUS_CODE AS statusCode, v.DESCRIPTION, v.DEFAULT_YN,
p.PROJECT_NAME, u.USER_NAME AS projectOwnerName
FROM PROJECT_VERSION v LEFT JOIN PROJECT p ON v.PROJECT_ID = p.PROJECT_ID LEFT JOIN USERS u ON p.OWNER_ID = u.USER_ID WHERE v.PROJECT_ID = #{projectId} AND v.VERSION_ID = #{versionId}
